def {{nama_fungsi_enc}}(text, url_safe=False):
    """Encode string to base64. Returns string."""
    data = text.encode('utf-8') if isinstance(text, str) else text
    if url_safe:
        return base64.urlsafe_b64encode(data).decode('ascii')
    return base64.b64encode(data).decode('ascii')


def {{nama_fungsi_dec}}(encoded, url_safe=False):
    """Decode base64 string. Returns string."""
    data = encoded.encode('ascii') if isinstance(encoded, str) else encoded
    if url_safe:
        return base64.urlsafe_b64decode(data).decode('utf-8')
    return base64.b64decode(data).decode('utf-8')


def {{nama_fungsi_file_enc}}(input_path, output_path, url_safe=False):
    """Encode file to base64 and write to output file."""
    with open(input_path, 'rb') as f:
        data = f.read()
    if url_safe:
        encoded = base64.urlsafe_b64encode(data)
    else:
        encoded = base64.b64encode(data)
    with open(output_path, 'wb') as f:
        f.write(encoded)
    return len(encoded)


def {{nama_fungsi_file_dec}}(input_path, output_path, url_safe=False):
    """Decode base64 file to original binary."""
    with open(input_path, 'rb') as f:
        data = f.read()
    if url_safe:
        decoded = base64.urlsafe_b64decode(data)
    else:
        decoded = base64.b64decode(data)
    with open(output_path, 'wb') as f:
        f.write(decoded)
    return len(decoded)

def {{nama_fungsi_enc}}(obj):
    """Encode Python object to bytes. Supports: None, bool, int, float, str, list, dict.
    Format: [type_byte][payload]. NOT compatible with real MessagePack spec — simplified version.
    """
    if obj is None:
        return b'\xc0'
    if isinstance(obj, bool):
        return b'\xc3' if obj else b'\xc2'
    if isinstance(obj, int):
        if -128 <= obj <= 127:
            return b'\xd0' + obj.to_bytes(1, 'big', signed=True)
        if -32768 <= obj <= 32767:
            return b'\xd1' + obj.to_bytes(2, 'big', signed=True)
        return b'\xd2' + obj.to_bytes(4, 'big', signed=True)
    if isinstance(obj, float):
        import struct
        return b'\xcb' + struct.pack('>d', obj)
    if isinstance(obj, str):
        encoded = obj.encode('utf-8')
        length = len(encoded)
        if length < 32:
            return bytes([0xa0 | length]) + encoded
        return b'\xd9' + length.to_bytes(1, 'big') + encoded
    if isinstance(obj, (list, tuple)):
        items = b''.join({{nama_fungsi_enc}}(item) for item in obj)
        length = len(obj)
        if length < 16:
            return bytes([0x90 | length]) + items
        return b'\xdc' + length.to_bytes(2, 'big') + items
    if isinstance(obj, dict):
        pairs = b''
        for k, v in obj.items():
            pairs += {{nama_fungsi_enc}}(k) + {{nama_fungsi_enc}}(v)
        length = len(obj)
        if length < 16:
            return bytes([0x80 | length]) + pairs
        return b'\xde' + length.to_bytes(2, 'big') + pairs
    raise TypeError('Unsupported type: ' + type(obj).__name__)


def {{nama_fungsi_dec}}(data):
    """Decode bytes produced by {{nama_fungsi_enc}}. Returns (value, bytes_consumed)."""
    if isinstance(data, (bytes, bytearray)):
        result, _ = _msgpack_decode_at(data, 0)
        return result
    raise TypeError('Expected bytes, got ' + type(data).__name__)


def _msgpack_decode_at(data, pos):
    b = data[pos]
    if b == 0xc0:
        return None, pos + 1
    if b == 0xc2:
        return False, pos + 1
    if b == 0xc3:
        return True, pos + 1
    if b == 0xd0:
        return int.from_bytes(data[pos+1:pos+2], 'big', signed=True), pos + 2
    if b == 0xd1:
        return int.from_bytes(data[pos+1:pos+3], 'big', signed=True), pos + 3
    if b == 0xd2:
        return int.from_bytes(data[pos+1:pos+5], 'big', signed=True), pos + 5
    if b == 0xcb:
        import struct
        return struct.unpack('>d', data[pos+1:pos+9])[0], pos + 9
    if 0xa0 <= b <= 0xbf:
        length = b & 0x1f
        return data[pos+1:pos+1+length].decode('utf-8'), pos + 1 + length
    if b == 0xd9:
        length = data[pos+1]
        return data[pos+2:pos+2+length].decode('utf-8'), pos + 2 + length
    if 0x90 <= b <= 0x9f:
        count = b & 0x0f
        pos += 1
        items = []
        for _ in range(count):
            item, pos = _msgpack_decode_at(data, pos)
            items.append(item)
        return items, pos
    if b == 0xdc:
        count = int.from_bytes(data[pos+1:pos+3], 'big')
        pos += 3
        items = []
        for _ in range(count):
            item, pos = _msgpack_decode_at(data, pos)
            items.append(item)
        return items, pos
    if 0x80 <= b <= 0x8f:
        count = b & 0x0f
        pos += 1
        d = {}
        for _ in range(count):
            k, pos = _msgpack_decode_at(data, pos)
            v, pos = _msgpack_decode_at(data, pos)
            d[k] = v
        return d, pos
    if b == 0xde:
        count = int.from_bytes(data[pos+1:pos+3], 'big')
        pos += 3
        d = {}
        for _ in range(count):
            k, pos = _msgpack_decode_at(data, pos)
            v, pos = _msgpack_decode_at(data, pos)
            d[k] = v
        return d, pos
    raise ValueError('Unknown msgpack byte: 0x' + hex(b))

def {{nama_fungsi}}(xml_input, attr_prefix='{{attr_prefix}}', text_key='{{text_key}}'):
    """Convert XML string or file path to nested dict.
    Attributes prefixed with attr_prefix (default '@').
    Text content stored under text_key (default '#text').
    Repeated tags become lists.
    """
    if isinstance(xml_input, str) and not xml_input.strip().startswith('<'):
        tree = xml.etree.ElementTree.parse(xml_input)
        root = tree.getroot()
    else:
        root = xml.etree.ElementTree.fromstring(xml_input)
    return _element_to_dict(root, attr_prefix, text_key)


def _element_to_dict(elem, attr_prefix, text_key):
    result = {}
    for attr_name, attr_val in elem.attrib.items():
        result[attr_prefix + attr_name] = attr_val
    children = list(elem)
    if not children:
        text = (elem.text or '').strip()
        if result:
            if text:
                result[text_key] = text
        else:
            return text if text else None
    else:
        for child in children:
            child_dict = _element_to_dict(child, attr_prefix, text_key)
            tag = child.tag
            if tag in result:
                existing = result[tag]
                if isinstance(existing, list):
                    existing.append(child_dict)
                else:
                    result[tag] = [existing, child_dict]
            else:
                result[tag] = child_dict
        text = (elem.text or '').strip()
        if text:
            result[text_key] = text
    return result

def {{nama_fungsi}}(data, root_tag='root', attr_prefix='{{attr_prefix}}', text_key='{{text_key}}'):
    """Convert nested dict to XML string.
    Keys starting with attr_prefix become attributes.
    Key matching text_key becomes element text.
    List values create repeated elements.
    """
    root = _build_element(root_tag, data, attr_prefix, text_key)
    return xml.etree.ElementTree.tostring(root, encoding='unicode', xml_declaration=False)


def _build_element(tag, data, attr_prefix, text_key):
    import xml.etree.ElementTree as ET
    elem = ET.Element(tag)
    if isinstance(data, dict):
        for key, value in data.items():
            if key.startswith(attr_prefix):
                attr_name = key[len(attr_prefix):]
                elem.set(attr_name, str(value))
            elif key == text_key:
                elem.text = str(value)
            elif isinstance(value, list):
                for item in value:
                    child = _build_element(key, item, attr_prefix, text_key)
                    elem.append(child)
            elif isinstance(value, dict):
                child = _build_element(key, value, attr_prefix, text_key)
                elem.append(child)
            else:
                child = ET.Element(key)
                child.text = str(value) if value is not None else ''
                elem.append(child)
    elif data is not None:
        elem.text = str(data)
    return elem

class {{nama_class}}:
    """Newline Delimited JSON (NDJSON/JSONL) reader and writer.
    Each line is a separate JSON object. Streaming-friendly.
    """
    def __init__(self, filepath, mode='r', encoding='utf-8'):
        self.filepath = filepath
        self.mode = mode
        self.encoding = encoding
        self._file = None

    def __enter__(self):
        self._file = open(self.filepath, self.mode, encoding=self.encoding)
        return self

    def __exit__(self, *exc):
        if self._file:
            self._file.close()

    def read_all(self):
        """Read all lines, parse each as JSON. Returns list of objects."""
        results = []
        with open(self.filepath, 'r', encoding=self.encoding) as f:
            for line in f:
                line = line.strip()
                if line:
                    results.append(json.loads(line))
        return results

    def read_stream(self):
        """Yield parsed JSON objects one by one (generator)."""
        with open(self.filepath, 'r', encoding=self.encoding) as f:
            for line in f:
                line = line.strip()
                if line:
                    yield json.loads(line)

    def write_all(self, items):
        """Write list of objects as NDJSON."""
        with open(self.filepath, 'w', encoding=self.encoding) as f:
            for item in items:
                f.write(json.dumps(item, ensure_ascii=False) + '\n')

    def append(self, item):
        """Append one JSON object as a new line."""
        with open(self.filepath, 'a', encoding=self.encoding) as f:
            f.write(json.dumps(item, ensure_ascii=False) + '\n')

    @staticmethod
    def count_lines(filepath, encoding='utf-8'):
        """Count number of non-empty lines."""
        count = 0
        with open(filepath, 'r', encoding=encoding) as f:
            for line in f:
                if line.strip():
                    count += 1
        return count
